
class SecretVolumeSource {final String secretName; final List<KeyToPath>? items; final int? defaultMode; final bool? optional; SecretVolumeSource({required this.secretName, this.items, this.defaultMode, this.optional}); factory SecretVolumeSource.fromJson(Map<String, dynamic> json) {return SecretVolumeSource(secretName: json['secretName'], items: json['items'] != null ? (json['items'] as List).map((e) => KeyToPath.fromJson(e)).toList() : null, defaultMode: json['defaultMode'], optional: json['optional']);} Map<String, dynamic> toJson() {return {'secretName' : secretName, if (items != null) 'items' : items!.map((e) => e.toJson()).toList(), if (defaultMode != null) 'defaultMode' : defaultMode, if (optional != null) 'optional' : optional};}}
